+  private getHeadings(text: string, tocStart: number, tocEnd: number, options: AutoTocOptions): Heading[] {
+    const headings: Heading[] = [];
+    const anchors = new Map<string, number>();
+    let offset = 0;
+    let inFence: string = null;
+    let inMath = false;
+    let inYaml = false;
+    const lines = text.split(/(?<=\
)/);
